window.__QUIZ_DATA__=[{"id":"theory>Geography>1993>1>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Account for the rapid growth of world population in the last two decades","images":[],"marking_scheme":"(i) Modernization of agriculture leading to plentiful and varied food supply    (ii) Improved health services    (iii) Knowledge of the cause of infectious diseases and how to prevent them    (iv) Better sanitation    (v) Reduced infant mortality rate as a result of better care    (vi) A lowering of the marriage age from 22 to 20 and below    (vii) Change in child bearing pattern as women want to have all their children at once and have a rest later    (viii) Modernization and industrialization make standard of living to improve.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>1>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain any three problems arising from this rapid growth","images":[],"marking_scheme":"(i) Problem of housing (accommodation)    (ii) Problem of transportation    (iii) Shortage of food (or starvation)","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>1>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain any three problems arising from this rapid growth","images":[],"marking_scheme":"(i) Government and other agencies should establish residential estates    (ii) More roads, railways and other transportation network to take care of the increasing population    (iii) Mechanized agriculture should be practised.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>2>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Differentiate clearly between urban settlements and rural settlements","images":[],"marking_scheme":"Urban settlement is a relatively large, dense and permanent settlement of socially heterogeneous individuals usually found in towns, cities or megalopolis while rural settlement is a relatively small and scattered settlement of socially and culturally homogenous individuals found in villages or hamlets.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>2>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Explain four factors responsible for tl-increase in size of urban settlements","images":[],"marking_scheme":"(i) Availability of jobs (or employments)    (ii) Presence of social amenities, e.g electricity, water    (iii) Presence of administrative headquarters in urban area    (iv) Involvement of people in commercial and industrial activities in urban areas","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>2>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight four problems associated with such growth.","images":[],"marking_scheme":"(i) Inadequate transport facilities    (ii) Undue increase in human and vehicular traffic    (iii) Overuse and deterioration of available social services    (iv) increase in the rate of crimes.","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>3>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Explain, giving examples, four ways in which physical factors may hinder the development of road transportation","images":[],"marking_scheme":"(i) Rugged highlands create pattern for the development of roads    (ii) Climatic factors like rainfall can wash away existing roads or make it more difficult to construct new ones    (iii) Rivers, especially large ones do contribute greatly to the development of roads as huge amount is spent in the construction and erection of bridges    (iv) Swampy area is also a problem as it also takes large amount of money to construct bridges and flyovers across them.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>3>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Discuss any four factors responsible for the poor network of railways in tropical African countries","images":[],"marking_scheme":"(i) Capital costs for maintenance and operation of rail transport are usually high    (ii) Lack of spare parts and technical know-how tend to reduce the rail transportation    (iii) Rail lines are constructed only around mineral or agricultural producing areas hence the absence of these products results in low development of rail    (iv) it is relatively too slow and people do not want to travel with it.","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>4>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe three ways in which light industries differ from heavy industries","images":[],"marking_scheme":"Light industriesHeavy industriesThey produce relatively small light weight goods e.g shoesThey produce heavy and bulky goods e.g iron and steelThe products of light industries are mainly final or consumer goodsProducts are not final nor consumer good rather they are used in construction or manufacturing industriesIt usually employs a lot of female workersIt employs male workers due to the nature of work involved","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>4>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Give four reasons why light industries are more prevalent than heavy industries in tropical Africa.","images":[],"marking_scheme":"(i) Lack of capital; Poor funding leads to the establishment of light industries than heavy industries    (ii) Lack of technical know-how: Africans do not have the skills for heavy industrial operations    (iii) Lack of raw materials; Raw materials: for heavy, industries are lacking in African countries    (iv) Africans generally tend to engage in production of consumable goo than non-consumable goods because of the low level of development.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>5>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Give four reasons why countries engage in world trade","images":[],"marking_scheme":"(i) Uneven distribution of natural resources, e.g minerals    (ii) Differences in climate resulting in production of different crops in different countries    (iii) The need to generate foreign exchange    (iv) Differences in technical know-how and expertise for the production of mechanised goods a electronics.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>5>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"How have these reasons affected the volume of trade between Nigeria and her neighbouring countries?","images":[],"marking_scheme":"(i) Minerals which are not found in Nigeria are imported from neighbouring countries while Nigeria exports her minerals like petroleum to others which do not have it    (ii) Due to differences in climate, some crops which cannot be grown in Nigeria are imported while those that can be grown are exported. But because Nigeria a her neighbours have almost the same climate, the volume of trade tends to be reduced    (iii) There is reduction of t volume of trade between Nigeria and her neighbours because they do not have the technical know-how to produce goods    (iii) Foreign exchange earnings between Nigeria and her neighbours is also very low because they produce almost the same types of goods or products.","marks":"1","difficulty":"3"},{"id":"theory>Geography>1993>5>c>i","subject":"Geography","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name any two sea routes through which Nigeria trades with the outside world","images":[],"marking_scheme":"-South Atlantic route  -The Cape route","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>5>c>ii","subject":"Geography","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Indicate one commodity that Nigeria engages exports through each route","images":[],"marking_scheme":"petroleum (crude oil)","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>6>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On an outline map of Nigeria, locate and name  (i) one inland drainage basin  (ii) three rivers that flow into the basin  (iii) the Bight of Benin and Bight of Bonny  (iv) the Idanre Hill, Oban Hills and Biu plateau","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1993>6>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Account for the shallowness of the rivers and the lake of the inland drainage basin","images":[],"marking_scheme":"(i) Water from these rivers always flows into Lake Chad without flowing out    (ii) Silt and other weathered rock materials continue to drop into the lakes    (iii) There is the high evaporation of water in the rivers and the lakes.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>6>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe any four benefits of the lake.","images":[],"marking_scheme":"(i) For irrigation purposes    (ii) For fishing    (iii) For transportation of goods and people    (iv) For domestic and industrial uses, e.g drinking","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>7>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Distinguish between internal trade and international trade","images":[],"marking_scheme":"Internal trade involves the trade in goods within country while international trade is the type of tade done between one country and another","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>7>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name four commodities of internal trade in Nigeria, - two originating from the north and two from the south","images":[],"marking_scheme":"From the north are  (a) Cattle and  (b) Groundnut    From the south are  (a) Palm oil and  (b) Kola","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>7>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Identify the factors that promote trade between the northern and southern parts of Nigeria","images":[],"marking_scheme":"(i) Differences in the production of certain goods. Goods produced in the North are different from goods produce in the south, hence the need to exchange goods    (ii) Efficient transportation. e.g road, railway, etc.    (iii) Use of the same currency    (iv) Favourable price attached to the commodities involved in internal trade","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>7>d","subject":"Geography","year":"1993","type":"Theory","sub_label":"d","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"What are the limitations to internal trade in Nigeria?","images":[],"marking_scheme":"(i) Long distance between point of production and point of sales    (ii) Language barrier    (iii) High cost of transportation    (iv) Perishability of products.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>8>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Explain any two of the following methods of farming as adopted in Nigeria  (i) Mixed farming  (ii) Intensive farming  (iii) Plantation agriculture","images":[],"marking_scheme":"Mixed farming; is the type of farming in which farmers grow crops and also rear animals on the sal piece of land. Farmers grow certain crops and rear animals on the same land.    Plantation agriculture; involves the cultivation of a single crop over a large area of land. Modern implements like tractor, plop harrow, planters, etc, are used in plantation agriculture In most cases, cash crops especially tree crops a grown in plantation agriculture and the produce an mainly for sale.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>8>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"State three problems facing agriculture in Nigeria","images":[],"marking_scheme":"(i) Lack of finance or credit facilities.    (ii) Inadequate land due to land tenure system    (iii) Lack of storage and processing facilities.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>8>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"In what ways are these problems being solved?","images":[],"marking_scheme":"(i) Government should easily grant loans to farmers    (ii) Land should be made available to prospective farmers through the land decree of 1978    (iii) Government should provide storage and processing facilities at reduced rate.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>9>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On an outline map of Nigeria, show the main soil zones","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1993>9>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Name any one crop that is grown in each of the zones shown on your map","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"1"},{"id":"theory>Geography>1993>9>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Describe the soil characteristics that have favoured the cultivation of the type of crops in each zone.","images":[],"marking_scheme":"Soil characteristics that have favoured the cultivation of cocoa (Zones C):    (i) The land is undulating    (ii) It has well drained surface    (iii) It has a deep clayey and rich-in-acid soil.    Soil characteristics that favoured the cultivation of groundnut (Zone A):    (i) The soil has a wide plain    (ii) The top soil (A - Horizon) is humus    (iii) The soil is loose and sandy.    Soil characteristics that favoured the cultivation of yam (ZoneB):    (i) Well drained soil    (ii) Soil is sandy loam    (iii) It is not acidic and it is well aerated.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>10>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline any four factors that have encouraged the concentration of industries in the Lagos area","images":[],"marking_scheme":"(i) Nearness to power    (ii) Availability of labour    (iii) Availability of good roads    (iv) Nearness to market","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>10>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight the significance of the concentration to the inhabitants of the area.","images":[],"marking_scheme":"(i) It leads to the production of cheaper goods    (ii) It ensures specialisation    (iii) Labour is easily provided    (iv) It leads to exchange of ideas","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>11>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"On a sketch map of West Africa, show and name (i) the home areas of the Ashanti, the Wolof and the Mandingo  (ii) two areas with a population density of over 100 persons per km2  (iii) two areas with a population density of less than 5 persons per km2","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1993>11>b>i","subject":"Geography","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain how the variation in population density in West Africa has been aided by the following: Historical factors","images":[],"marking_scheme":"Historical factors: These have contributed to the variation in the population density in West Africa because ancient cities that developed like Kano, Katsina, Timbuktu are due to trans-saharan trade which took place several years ago. The population of these areas grew because of natural defence during war and being the sites of traditional empires those days","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>11>b>ii","subject":"Geography","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Explain how the variation in population density in West Africa has been aided by the following: Agriculture","images":[],"marking_scheme":"Agricultural activities tend to have possible effects on population distribution e.g the eastern Nigeria, part of Ashanti developed with high population because of intensive agricultural activities due to fertility of the soil, but where the land is not fertile, people tend to abandon such areas","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>11>b>iii","subject":"Geography","year":"1993","type":"Theory","sub_label":"iii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Explain how the variation in population density in West Africa has been aided by the following:  Mining","images":[],"marking_scheme":"Mining; The presence of minerals in certain areas tends to attract high population because of availability of jobs and other facilities in the areas","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>11>b>iv","subject":"Geography","year":"1993","type":"Theory","sub_label":"iv","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain how the variation in population density in West Africa has been aided by the following: Industrialisation","images":[],"marking_scheme":"Industrialisation. People tend to move to places where there are many industries , as these will help to provide job and improve the standard of living of the people.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>12>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On a sketch map of Africa, show and name:  (I) Cape Verde and the Cape of Good Hope  (ii) the Rivers Nile, Niger and Orange  (iii) the East African rift valley  (iv) one fold mountain in the north and one in the south","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>12>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"In what three ways are the highlands of Africa economically important?","images":[],"marking_scheme":"(i) They contribute to the formation of relief rainfall    (ii) Minerals are found in highlands    (iii) Highlands serve as sources of rivers","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>12>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Describe three ways in which the rivers of Africa are of importance.","images":[],"marking_scheme":"(i) Generation of hydro-electricity    (ii) Serve as sources of water for domestic and industrial uses    (iii) Fishing is done in rivers","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>13>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"On a sketch map of Africa, mark and name:  (i) one area receiving rainfall throughout the year  (ii) one area receiving rainfall in summer only  (iii) one warm ocean current (indicating the direction of flow)  (iv) one cold ocean current (indicating the direction of flow)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"1","difficulty":"3"},{"id":"theory>Geography>1993>13>b>i","subject":"Geography","year":"1993","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Identify the type of nature vegetation found in each of the areas shown on your map","images":[],"marking_scheme":"Area with rainfall is throughout the year is equatorial forest    (The type of vegetation found in areas of summer rainfall is savanna grassland","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>13>b>ii","subject":"Geography","year":"1993","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"How has rainfall accounted for the difference in vegetation in the two areas?","images":[],"marking_scheme":"As a result of continuous rainfall, the vegetation becomes evergreen with tall trees. The trees are of different layers with canopies. But due to rainfall only in summer the trees are deciduous. i.e the trees shed the leaves during the dry season so as to conserve sufficient water. Hence most of the plants found are mainly grasses.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>14>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Give reasons for each of any three of the following:    the importance of fruit farming in the Mediterranean lands","images":[],"marking_scheme":"Importance of fruit farming in the Mediterranean lands include:    (i) Fruits like oranges, bananas, pineapples are consumed in many homes and are also processed into various forms of juices    (ii) Most of the fruits produced are for export to European market thereby generating foreign exchange    (iii) It also provides employment opportunities to people    (iv) Provides raw materials for canning and processing industries    (v) Wine is obtained from processing of vines which are produced in the Mediterranean lands.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>14>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Give reasons for each of any three of the following:  the predominance of lumbering in the Zaire basin","images":[],"marking_scheme":"The predominance of lumbering in Zaire basin.    (i) The dense equatorial forest is a source of valuable timber (50%) of Zaire is forested)    (ii) River Zaire and its numerous tributaries provide means of transporting the logs to sawmills or to ports for export    (iii) There is ready market for the sawn timber both internally and externally    (iv) There is high demand for timber as fuel","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>14>c","subject":"Geography","year":"1993","type":"Theory","sub_label":"c","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Give reasons for each of any three of the following:  the declining importance of bush fallowing in WestAfrica","images":[],"marking_scheme":"The declining importance of bush fallowing in West Africa:- Bush fallow system of Agriculture in West Africa has declined in importance for the following reasons :-    Mechanization of Agriculture (use of tractors on farmland) has increased in recent times which has in turn increased the sizes of the farm taking over parts of land that could be used for fallow.    Due to the mechanized nature of Agriculture cash crops like cocoa, oil palm cotton, coffee etc. have been introduced thereby changing system of land ownership and system of farming.    There has been an increase in population in recent times leading to an increase in demand for land resulting in the shortening of period of fallow leading to decrease in yields.    Individual land ownership has replaced communal land ownership leading to introduction of other systems of agriculture e.g. introduction of fertilizers.","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>14>d","subject":"Geography","year":"1993","type":"Theory","sub_label":"d","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AGRICULTURE","question":"Give reasons for each of any three of the following:  the importance of plantation agriculture in EastAfrica.","images":[],"marking_scheme":"The importance of plantation agriculture in East Africa    (i) Local people learn new skills in the job as machine operators, seed planters etc    (ii) It provides employment opportunities to the people    (iii) Plantation agriculture helps in bringing about general development in the area where it is practised","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>15>a","subject":"Geography","year":"1993","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Outline any three achievements of the Economic Community of West African States (ECOWAS) since its formation","images":[],"marking_scheme":"(i) There is now free movement of people between the countries as travel visas for visits not lasting more than three months were abolished in 1979    (ii) Border dispute between Benin and Togo was resolved in the spirit of ECOWAS in 1975    (iii) The ECOWAS games held in Lagos in 1977 aided understanding and solidarity among the states","marks":"1","difficulty":"2"},{"id":"theory>Geography>1993>15>b","subject":"Geography","year":"1993","type":"Theory","sub_label":"b","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"What five problems are facing the ECOWAS in the achievement of its objectives?","images":[],"marking_scheme":"(i) The division of West African states along linguistic lines (English and French) discourages the coming together of the two groups.    (ii) Many of the states are unable to pay their annual dues. This makes the running of the secretariat difficult.    (iii) The smaller and poor countries fear that the bigger and richer ones will dominate them economically and politically    (iv) Some of the richer countries are also suspicious that their resources might be tapped to enrich poorer countries    (v) The countries as they become independent adopted their own different currencies. This has complicated trade","marks":"1","difficulty":"2"}];